package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreHeaderCase() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat newFormat = format.withIgnoreHeaderCase(true);

        assertNotNull(newFormat);
        assertTrue(newFormat.getIgnoreHeaderCase());
        // Original format should remain unchanged
        assertFalse(format.getIgnoreHeaderCase());
        // The new instance should be different from the original
        assertNotSame(format, newFormat);
    }
}
